filename = fullpath(getIPCVpath() + "/images/dicom/emri_small.dcm");
[volume, info] = dicomread(filename);
viewer = volshow(volume, info);

filename = fullpath(getIPCVpath() + "/images/dicom/emri_small.dcm");
options = struct( ..
    "RenderingStyle", "mip", ..
    "Colormap", "bone", ..
    "Quality", 192, ..
    "Threshold", 0.12);
viewer = volshow(filename, options);

filename = fullpath(getIPCVpath() + "/images/dicom/emri_small.dcm");
options = struct("RenderingStyle", "2d", "Colormap", "gray");
viewer = volshow(filename, options);
// Select a layer in the GUI and export it as volshow_layer.

[x, y, z] = ndgrid(1:96, 1:96, 1:64);
volume = exp(-((x - 48).^2 + (y - 48).^2 + (z - 32).^2) / 500);
options = struct("RenderingStyle", "isosurface", "Threshold", 0.42);
viewer = volshow(volume, options);
